ROLLBACK = "from __future__ import annotations\n\nimport argparse\nimport json\nimport shutil\nfrom pathlib import Path\n\nPATCH_ID = \"4B436634E\"\nFILES = [\n    \"README_APPLY_4B436634E.txt\",\n    \"docs/TRANSITION_APPROVAL_DRY_RUN_4B436634E.md\",\n    \"src/tradebot/transition_approval_dry_run.py\",\n    \"tests/test_transition_approval_dry_run_4B436634E.py\",\n    \"tools/check_4B436634E_transition_approval_dry_run.py\",\n    \"tools/run_4B436634E_transition_approval_dry_run.py\",\n]\n\n\ndef main() -> int:\n    parser = argparse.ArgumentParser(description=\"Rollback 4B436634E files\")\n    parser.add_argument(\"--backup-root\", default=\"\")\n    args = parser.parse_args()\n    repo = Path.cwd()\n    restored: list[str] = []\n    removed: list[str] = []\n    backup_root = repo / args.backup_root if args.backup_root else None\n    for rel in FILES:\n        path = repo / rel\n        backup = backup_root / rel if backup_root else None\n        if backup is not None and backup.exists():\n            path.parent.mkdir(parents=True, exist_ok=True)\n            shutil.copy2(backup, path)\n            restored.append(rel)\n        elif path.exists():\n            path.unlink()\n            removed.append(rel)\n    print(json.dumps({\"patch_id\": PATCH_ID, \"restored_files\": restored, \"removed_files\": removed}, indent=2, sort_keys=True))\n    return 0\n\n\nif __name__ == \"__main__\":\n    raise SystemExit(main())\n"


def utc_timestamp() -> str:
    return datetime.now(timezone.utc).strftime("%Y%m%dT%H%M%SZ")


def main() -> int:
    repo = Path.cwd()
    backup_root = repo / "tools" / f"_patch_backup_{PATCH_ID}_{utc_timestamp()}"
    written_files: list[str] = []
    backed_up_files: list[str] = []
    modified_files: list[str] = []

    all_payloads = dict(PAYLOADS)
    all_payloads["tools/rollback_4B436634E_transition_approval_dry_run.py"] = ROLLBACK

    for rel, content in all_payloads.items():
        path = repo / rel
        path.parent.mkdir(parents=True, exist_ok=True)
        if path.exists():
            backup_path = backup_root / rel
            backup_path.parent.mkdir(parents=True, exist_ok=True)
            shutil.copy2(path, backup_path)
            backed_up_files.append(rel)
            modified_files.append(rel)
        path.write_text(content, encoding="utf-8")
        written_files.append(rel)

    compile_errors: dict[str, str] = {}
    for rel in written_files:
        if rel.endswith(".py"):
            try:
                py_compile.compile(str(repo / rel), doraise=True)
            except py_compile.PyCompileError as exc:
                compile_errors[rel] = str(exc)

    result: dict[str, Any] = {
        "applied": not compile_errors,
        "patch_id": PATCH_ID,
        "patch_version": PATCH_VERSION,
        "patch_name": PATCH_NAME,
        "written_files": written_files,
        "modified_files": modified_files,
        "backed_up_files": backed_up_files,
        "backup_root": str(backup_root.relative_to(repo)) if backed_up_files else "",
        "py_compile_ok": not compile_errors,
        "compile_errors": compile_errors,
        "approved_for_live_real": False,
        "approved_for_paper_transition": False,
        "approved_for_exchange_submit": False,
        "approved_for_runtime_overlay": False,
        "next_phase_unlock_performed": False,
        "transition_to_next_phase_performed": False,
        "handoff_performed": False,
        "deduplication_action_performed": False,
        "report_delete_performed": False,
        "file_move_performed": False,
        "archive_execution_allowed": False,
        "archive_move_performed": False,
        "file_delete_performed": False,
        "destructive_cleanup_performed": False,
        "exchange_submit_performed": False,
        "order_submit_performed": False,
        "trading_action_performed": False,
        "training_performed": False,
        "reload_performed": False,
        "runtime_overlay_activated": False,
    }
    print(json.dumps(result, indent=2, sort_keys=True, ensure_ascii=False))
    return 0 if not compile_errors else 2


if __name__ == "__main__":
    raise SystemExit(main())
